"use client"
import { useEffect, useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Points, PointMaterial } from '@react-three/drei';
import * as random from 'maath/random/dist/maath-random.esm';
import { Sparkles, Music, Code, Palette, Activity } from 'lucide-react';
import Link from 'next/link';

// Background Particles System
function ParticleSystem(props: any) {
  const ref = useRef<any>();

  // Create a sphere of random points
  const sphere = random.inSphere(new Float32Array(5000), { radius: 1.5 });

  useFrame((state, delta) => {
    if (ref.current) {
      ref.current.rotation.x -= delta / 10;
      ref.current.rotation.y -= delta / 15;
    }
  });

  return (
    <group rotation={[0, 0, Math.PI / 4]}>
      <Points ref={ref} positions={sphere} stride={3} frustumCulled={false} {...props}>
        <PointMaterial
          transparent
          color="#ff8c5a"
          size={0.005}
          sizeAttenuation={true}
          depthWrite={false}
        />
      </Points>
    </group>
  );
}

// Floating Event Elements
function FloatingIcon({ Icon, color, className, delay }: { Icon: any, color: string, className: string, delay: string }) {
  return (
    <div 
      className={`absolute hidden md:flex items-center justify-center w-16 h-16 rounded-2xl glass-panel ${className}`}
      style={{ animation: `float-slow 8s ease-in-out infinite ${delay}` }}
    >
      <Icon size={32} color={color} className="drop-shadow-neon" />
    </div>
  );
}

export default function Hero() {
  return (
    <section className="relative h-screen w-full overflow-hidden flex flex-col items-center justify-center">

      {/* 3D Particle Background */}
      <div className="absolute inset-0 z-0 opacity-60">
        <Canvas camera={{ position: [0, 0, 1] }}>
          <ParticleSystem />
        </Canvas>
      </div>

      {/* Decorative Radial Gradients */}
      <div className="absolute top-1/4 left-1/4 w-[40rem] h-[40rem] bg-brand-purple-600/20 rounded-full blur-[120px] mix-blend-screen pointer-events-none" />
      <div className="absolute bottom-1/4 right-1/4 w-[30rem] h-[30rem] bg-brand-orange-500/10 rounded-full blur-[100px] mix-blend-screen pointer-events-none" />

      {/* Floating Elements Background */}
      <div className="absolute inset-0 z-10 pointer-events-none">
         <FloatingIcon Icon={Music} color="#ffd700" className="top-[20%] left-[15%]" delay="0s" />
         <FloatingIcon Icon={Palette} color="#ff6b35" className="top-[60%] left-[10%]" delay="1s" />
         <FloatingIcon Icon={Code} color="#4a2b8e" className="top-[30%] right-[15%]" delay="2s" />
         <FloatingIcon Icon={Activity} color="#ffffff" className="top-[70%] right-[20%]" delay="1.5s" />
      </div>

      {/* Main Content */}
      <div className="relative z-20 w-full max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center mt-20">

        {/* Subtitle Badge */}
        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full glass-panel border-brand-orange-500/30 text-brand-orange-400 font-medium text-sm tracking-widest mb-8 animate-levitate shadow-neon">
          <Sparkles size={16} />
          <span>NATIONAL YOUTH FESTIVAL</span>
        </div>

        {/* Headline */}
        <h1 className="text-5xl md:text-7xl lg:text-8xl font-bold font-space leading-tight mb-6">
          Celebrating Every <br />
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-brand-orange-500 via-brand-gold-400 to-brand-orange-500 animate-pulse text-glow">
            Hue of Youth
          </span>
        </h1>

        {/* Subtext */}
        <p className="max-w-2xl mx-auto text-lg md:text-xl text-gray-300 mb-12 font-light leading-relaxed">
          India&apos;s vibrant national youth festival bringing together culture, innovation, art, sports, and creativity at CSJMU Kanpur.
        </p>

        {/* CTA Buttons */}
        <div className="flex flex-col sm:flex-row items-center justify-center gap-6">
          <Link 
            href="#register"
            className="w-full sm:w-auto px-8 py-4 rounded-full bg-gradient-to-r from-brand-orange-500 to-brand-gold-400 text-brand-purple-900 font-bold text-lg hover:shadow-neon hover:scale-105 transition-all duration-300 relative group overflow-hidden"
          >
            <span className="relative z-10">Register Now</span>
            <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300 ease-out" />
          </Link>

          <Link 
            href="#events"
            className="w-full sm:w-auto px-8 py-4 rounded-full glass-panel hover:bg-white/10 text-white font-bold text-lg transition-all duration-300"
          >
            Explore Events
          </Link>
        </div>
      </div>

      {/* Scroll Indicator */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-20 flex flex-col items-center gap-2 animate-bounce">
        <span className="text-xs uppercase tracking-widest text-gray-500 font-bold">Scroll</span>
        <div className="w-1 h-8 rounded-full bg-white/20 overflow-hidden">
          <div className="w-full h-1/2 bg-brand-orange-500 animate-slide-down" />
        </div>
      </div>

    </section>
  );
}
